CREATE PROCEDURE [dbo].[p]
AS
BEGIN
    DECLARE cur CURSOR LOCAL FAST_FORWARD FOR
        SELECT 1 AS Id
        UNION ALL
        SELECT 2 AS Id
    OPEN cur
END
GO

DECLARE c1 CURSOR FOR SELECT a FROM t1 UNION SELECT b FROM t2
GO

DECLARE c2 CURSOR FOR SELECT x FROM t1 INTERSECT SELECT y FROM t2 EXCEPT SELECT z FROM t3
GO

DECLARE c3 CURSOR LOCAL SCROLL FOR SELECT id FROM users ORDER BY id
GO